// ============================================================
// GIRO — Motor de Inteligência de Estoque
// Versão: 1.0 | ELEVARIA
// ============================================================

const items = $input.all();
const produtos = items.map(i => i.json);

// --- Helpers ---
const hoje = new Date();

function diasSemVenda(ultimaVenda) {
  if (!ultimaVenda) return 999;
  const d = new Date(ultimaVenda);
  return Math.floor((hoje - d) / (1000 * 60 * 60 * 24));
}

function coberturaDias(estoqueAtual, vendas30d) {
  if (!vendas30d || vendas30d == 0) return 999;
  const vendasDia = vendas30d / 30;
  return Math.round(estoqueAtual / vendasDia);
}

function giroMensal(vendas30d, estoqueAtual) {
  if (!estoqueAtual || estoqueAtual == 0) return 0;
  return parseFloat((vendas30d / estoqueAtual).toFixed(2));
}

// --- Processar cada produto ---
const processados = produtos.map(p => {
  const estoque = parseFloat(p.estoque_atual) || 0;
  const estoqueMin = parseFloat(p.estoque_minimo) || 0;
  const v30 = parseFloat(p.vendas_30d) || 0;
  const v90 = parseFloat(p.vendas_90d) || 0;
  const custo = parseFloat(p.preco_custo) || 0;
  const venda = parseFloat(p.preco_venda) || 0;
  const margem = venda > 0 ? ((venda - custo) / venda * 100) : 0;
  const faturamento30d = v30 * venda;
  const cobertura = coberturaDias(estoque, v30);
  const giro = giroMensal(v30, estoque);
  const diasSemMov = diasSemVenda(p.ultima_venda);
  const capitalParado = estoque * custo;

  // Classificação de status
  let status = 'normal';
  let alerta = null;

  if (estoque === 0 && v30 > 0) {
    status = 'ruptura';
    alerta = 'RUPTURA — produto sem estoque com demanda ativa';
  } else if (estoque > 0 && estoque < estoqueMin) {
    status = 'critico';
    alerta = `ESTOQUE CRÍTICO — abaixo do mínimo (${estoque} / mín. ${estoqueMin})`;
  } else if (diasSemMov > 90 && estoque > 0) {
    status = 'parado';
    alerta = `ESTOQUE PARADO — ${diasSemMov} dias sem venda`;
  } else if (cobertura > 120) {
    status = 'excesso';
    alerta = `EXCESSO — cobertura de ${cobertura} dias (mais de 4 meses)`;
  } else if (cobertura < 15 && v30 > 0) {
    status = 'reposicao';
    alerta = `REPOSIÇÃO URGENTE — apenas ${cobertura} dias de estoque`;
  }

  return {
    produto: p.produto,
    sku: p.sku || '-',
    estoque,
    estoqueMin,
    v30,
    v90,
    custo,
    venda,
    margem: margem.toFixed(1),
    faturamento30d: faturamento30d.toFixed(2),
    cobertura,
    giro,
    diasSemMov,
    capitalParado: capitalParado.toFixed(2),
    status,
    alerta
  };
});

// --- Curva ABC por faturamento ---
const totalFaturamento = processados.reduce((s, p) => s + parseFloat(p.faturamento30d), 0);
const ordenadoPorFat = [...processados].sort((a, b) => parseFloat(b.faturamento30d) - parseFloat(a.faturamento30d));
let acum = 0;
ordenadoPorFat.forEach(p => {
  acum += parseFloat(p.faturamento30d);
  const pct = totalFaturamento > 0 ? (acum / totalFaturamento * 100) : 0;
  p.curvaABC = pct <= 70 ? 'A' : pct <= 90 ? 'B' : 'C';
});

// Voltar classificação ABC ao array processados
processados.forEach(p => {
  const enc = ordenadoPorFat.find(x => x.sku === p.sku && x.produto === p.produto);
  if (enc) p.curvaABC = enc.curvaABC;
});

// --- Resumo executivo ---
const totalProdutos = processados.length;
const rupturas = processados.filter(p => p.status === 'ruptura');
const criticos = processados.filter(p => p.status === 'critico');
const parados = processados.filter(p => p.status === 'parado');
const excessos = processados.filter(p => p.status === 'excesso');
const reposicoes = processados.filter(p => p.status === 'reposicao');
const curvaA = processados.filter(p => p.curvaABC === 'A');

const totalCapitalParado = parados.reduce((s, p) => s + parseFloat(p.capitalParado), 0);
const totalFat30 = processados.reduce((s, p) => s + parseFloat(p.faturamento30d), 0);

const resumo = {
  totalProdutos,
  totalFaturamento30d: totalFat30.toFixed(2),
  totalCapitalParado: totalCapitalParado.toFixed(2),
  qtdRupturas: rupturas.length,
  qtdCriticos: criticos.length,
  qtdParados: parados.length,
  qtdExcessos: excessos.length,
  qtdReposicoes: reposicoes.length,
  qtdCurvaA: curvaA.length,
  produtosParados: parados.slice(0, 5).map(p => p.produto),
  produtosRuptura: rupturas.map(p => p.produto),
  produtosCriticos: criticos.slice(0, 5).map(p => `${p.produto} (${p.estoque} un)`),
  topCurvaA: curvaA.slice(0, 5).map(p => p.produto),
  dataAnalise: hoje.toLocaleDateString('pt-BR')
};

// --- Output ---
return [{
  json: {
    resumo,
    produtos: processados,
    alertas: processados.filter(p => p.alerta).map(p => ({ produto: p.produto, alerta: p.alerta, status: p.status }))
  }
}];

