const kpis = $('Calcular KPIs de Estoque').first().json;
const iaResponse = $input.first().json;

// Extrair texto da resposta da IA
const analise = iaResponse.content?.[0]?.text || 'Análise não disponível.';
const resumo = kpis.resumo;

// ---- Montar mensagem WhatsApp ----
const linhaRuptura = resumo.qtdRupturas > 0
  ? `🔴 *Ruptura de estoque:* ${resumo.qtdRupturas} produto(s) sem estoque\n`
  : '';

const linhaCritico = resumo.qtdCriticos > 0
  ? `🟠 *Estoque crítico:* ${resumo.qtdCriticos} produto(s) abaixo do mínimo\n`
  : '';

const linhaParado = resumo.qtdParados > 0
  ? `🟡 *Capital parado:* ${resumo.qtdParados} produto(s) sem giro — R$ ${parseFloat(resumo.totalCapitalParado).toLocaleString('pt-BR', {minimumFractionDigits: 2})} imobilizados\n`
  : '';

const mensagem = `🔄 *GIRO — Relatório de Estoque*
📅 ${resumo.dataAnalise}

━━━━━━━━━━━━━━━━━━━━
📊 *PAINEL RÁPIDO*

Produtos analisados: ${resumo.totalProdutos}
Faturamento (30 dias): R$ ${parseFloat(resumo.totalFaturamento30d).toLocaleString('pt-BR', {minimumFractionDigits: 2})}

${linhaRuptura}${linhaCritico}${linhaParado}
━━━━━━━━━━━━━━━━━━━━
🤖 *ANÁLISE E RECOMENDAÇÕES*

${analise}

━━━━━━━━━━━━━━━━━━━━
_Relatório gerado automaticamente pelo GIRO_
_Dúvidas? Fale com a ELEVARIA_`;

return [{ json: { mensagem, resumo } }];
